'use client'
import React, { useState } from 'react';
import { useBudget } from '@/context/BudgetContext';
import { User, Lock, ArrowRight, Loader, ShieldCheck } from 'lucide-react';
import { GoogleLogin } from '@react-oauth/google';

import { useRouter } from 'next/navigation';

const Login: React.FC = () => {
    const { login, loginWithGoogle } = useBudget();
    const router = useRouter();
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');

        try {
            const success = await login(username, password);
            if (success) {
                router.push('/dashboard');
            } else {
                setError('ชื่อผู้ใช้งานหรือรหัสผ่านไม่ถูกต้อง');
            }
        } catch (err: any) {
            console.error("Login Error Payload:", err);
            setError(`เกิดข้อผิดพลาดในการเข้าสู่ระบบ: ${err.message || err.toString()}`);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="h-screen w-full flex flex-col lg:flex-row overflow-hidden bg-white font-sans">
            {/* Branding Section - KTB Next Blue Gradient */}
            <div className="hidden lg:flex lg:w-1/2 p-16 bg-gradient-to-br from-primary-600 via-primary-500 to-primary-700 items-center justify-center relative overflow-hidden">
                <div className="absolute top-0 right-0 w-96 h-96 bg-white/10 rounded-full -mr-24 -mt-24 blur-3xl animate-pulse"></div>
                <div className="absolute bottom-0 left-0 w-80 h-80 bg-primary-400/20 rounded-full -ml-24 -mb-24 blur-3xl"></div>

                <div className="relative z-10 text-center space-y-10 max-w-sm">
                    <div className="inline-flex p-6 rounded-[32px] bg-white/10 backdrop-blur-md border border-white/20 shadow-2xl transition-transform hover:scale-110 duration-500">
                        <Wallet className="w-20 h-20 text-white" />
                    </div>
                    <div className="space-y-4">
                        <h2 className="text-5xl font-extrabold text-white tracking-tighter leading-tight italic drop-shadow-lg">
                            SMART BUDGET
                        </h2>
                        <p className="text-primary-50 text-lg font-medium tracking-wide opacity-90 leading-relaxed">
                            ยกระดับการบริหารงบประมาณด้วยเทคโนโลยี <br /> Digital Trust Platform ที่แม่นยำที่สุด
                        </p>
                    </div>
                    <div className="flex justify-center gap-3 pt-4">
                        {[1, 2, 3].map((i) => (
                            <div key={i} className={`h-1.5 rounded-full transition-all duration-500 ${i === 1 ? 'w-12 bg-white' : 'w-4 bg-white/30'}`}></div>
                        ))}
                    </div>
                </div>
                <div className="absolute bottom-8 left-12 text-[10px] text-white/30 tracking-[0.2em] font-mono uppercase">
                    Secured by DCC Platform • v2.0.0
                </div>
            </div>

            {/* Right Side */}
            <div className="flex-1 flex flex-col justify-center items-center p-6 bg-white overflow-y-auto">
                <div className="w-full max-w-[380px]">
                    {/* Header */}
                    <div className="mb-8 text-center sm:text-left">
                        <div className="w-14 h-14 bg-primary-50 rounded-[20px] flex items-center justify-center text-primary-600 mb-6 mx-auto sm:mx-0 border border-primary-100/50">
                            <ShieldCheck size={26} strokeWidth={2} />
                        </div>
                        <h2 className="text-[28px] font-bold text-gray-900 mb-2 tracking-tight">ยินดีต้อนรับกลับมา!</h2>
                        <p className="text-gray-500 text-[13.5px] font-medium">
                            เข้าสู่ระบบเพื่อดำเนินการบริหารงบประมาณ
                        </p>
                    </div>

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="space-y-5">
                        {error && (
                            <div className="px-4 py-3.5 mb-2 rounded-xl bg-red-50 border border-red-100 text-red-600 text-xs flex items-center gap-3 font-bold">
                                <span className="w-2 h-2 rounded-full bg-red-500 flex-shrink-0"></span>
                                {error}
                            </div>
                        )}

                        <div>
                            <label className="text-[13px] font-bold text-gray-800 mb-2 block tracking-tight">ชื่อผู้ใช้งาน</label>
                            <div className="relative group">
                                <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                                    <User className="h-4 w-4 text-gray-400 group-focus-within:text-primary-600 transition-colors" />
                                </div>
                                <input
                                    type="text"
                                    value={username}
                                    onChange={(e) => {
                                        setUsername(e.target.value);
                                        if (error) setError('');
                                    }}
                                    className="w-full pl-10 pr-4 py-3 focus:bg-white bg-[#F9FAFB] border border-gray-200 rounded-[10px] text-[13px] text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-primary-500 focus:border-primary-500 transition-all font-medium"
                                    placeholder="admin"
                                    required
                                />
                            </div>
                        </div>

                        <div>
                            <label className="text-[13px] font-bold text-gray-800 mb-2 block tracking-tight">รหัสผ่าน</label>
                            <div className="relative group">
                                <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                                    <Lock className="h-4 w-4 text-primary-500 group-focus-within:text-primary-600 transition-colors" />
                                </div>
                                <input
                                    type="password"
                                    value={password}
                                    onChange={(e) => {
                                        setPassword(e.target.value);
                                        if (error) setError('');
                                    }}
                                    className="w-full pl-10 pr-4 py-3 bg-white border border-primary-300 ring-1 ring-primary-100/50 rounded-[10px] text-sm text-primary-600 placeholder-primary-500 focus:outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500 transition-all font-black tracking-widest"
                                    placeholder="••••••••"
                                    required
                                />
                            </div>
                        </div>

                        <div className="relative mt-8 mb-6">
                            <div className="absolute inset-0 flex items-center">
                                <span className="w-full border-t border-gray-200"></span>
                            </div>
                            <div className="relative flex justify-center text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                                <span className="bg-white px-4">OR CONTINUE WITH</span>
                            </div>
                        </div>

                        <div className="flex justify-center mb-6">
                            <div className="w-[85%] sm:w-[75%] flex justify-center scale-105 origin-center">
                                <GoogleLogin
                                    onSuccess={async (credentialResponse) => {
                                        if (credentialResponse.credential) {
                                            setIsLoading(true);
                                            try {
                                                const success = await loginWithGoogle(credentialResponse.credential);
                                                if (!success) setError('Google Sign-In Failed');
                                            } catch (err) {
                                                setError('Google Sign-In Error');
                                            } finally {
                                                setIsLoading(false);
                                            }
                                        }
                                    }}
                                    onError={() => setError('Google Sign-In Failed')}
                                    shape="pill"
                                    theme="outline"
                                    text="signin_with"
                                />
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={isLoading}
                            className="w-full bg-[#005191] hover:bg-[#004478] text-white py-[14px] rounded-[10px] font-bold text-[14px] shadow-sm transform active:scale-[0.99] transition-all flex items-center justify-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
                        >
                            {isLoading ? (
                                <Loader className="animate-spin" size={18} />
                            ) : (
                                <>
                                    เข้าสู่ระบบ <ArrowRight size={16} strokeWidth={2.5} className="mt-0.5" />
                                </>
                            )}
                        </button>
                    </form>

                    {/* Footer */}
                    <div className="mt-8 text-center text-[11px] text-gray-500 flex flex-col gap-3">
                        <p>
                            ไม่มีบัญชีผู้ใช้งาน?{' '}
                            <span className="text-[#005191] font-bold cursor-pointer hover:underline">
                                ติดต่อผู้ดูแลระบบ
                            </span>
                        </p>
                        <p>
                            <a href="#" className="text-[#005191] font-bold hover:underline">
                                ลืมรหัสผ่าน?
                            </a>
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Login;
